import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:5000/api/transactions';

function App() {
  const [transactions, setTransactions] = useState([]);
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    description: '',
    category: 'Pemasukan',
    amount: ''
  });

  const fetchTransactions = async () => {
    try {
      setLoading(true);
      const response = await axios.get(API_URL);
      setTransactions(Array.isArray(response.data) ? response.data : []);
    } catch (error) {
      console.error("Gagal sinkronisasi data:", error);
      setTransactions([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTransactions();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    if (!formData.description || !formData.amount) {
      alert("Deskripsi dan nominal wajib diisi!");
      return;
    }
    try {
      await axios.post(API_URL, {
        date: formData.date,
        description: formData.description,
        category: formData.category,
        amount: parseFloat(formData.amount)
      });
      setFormData({
        date: new Date().toISOString().split('T')[0],
        description: '',
        category: 'Pemasukan',
        amount: ''
      });
      fetchTransactions();
      alert("✨ Transaksi sukses disimpan ke database!");
    } catch (error) {
      console.error("Error:", error);
      alert("Gagal menyimpan ke MySQL!");
    }
  };

  const totalPemasukan = transactions?.filter?.(t => t.category === 'Pemasukan')
    ?.reduce((sum, t) => sum + parseFloat(t.amount || 0), 0) || 0;

  const totalPengeluaran = transactions?.filter?.(t => t.category === 'Pengeluaran')
    ?.reduce((sum, t) => sum + parseFloat(t.amount || 0), 0) || 0;

  const sisaSaldo = totalPemasukan - totalPengeluaran;

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-slate-950 text-emerald-400 font-sans">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-emerald-400 border-t-transparent rounded-full animate-spin"></div>
          <div className="text-sm font-semibold tracking-wide uppercase animate-pulse">Menghubungkan ke Database...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950 text-slate-100 font-sans flex">
      
      {/* SIDEBAR PREMIUM */}
      <aside className="w-68 bg-slate-900/60 backdrop-blur-xl border-r border-slate-800/60 p-6 flex flex-col justify-between shrink-0">
        <div className="space-y-8">
          <div className="flex items-center space-x-3 border-b border-slate-800 pb-5">
            <div className="w-9 h-9 bg-gradient-to-tr from-emerald-400 to-teal-500 rounded-xl flex items-center justify-center font-black text-slate-950 shadow-lg shadow-emerald-500/20">
              🖲️
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">FINANCE PRO</h1>
              <p className="text-xs text-emerald-400/80 font-mono tracking-widest">RPL PROJECT</p>
            </div>
          </div>
          
          <nav className="space-y-1.5">
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider px-3 mb-2">Menu Utama</p>
            <button onClick={() => setActiveMenu('dashboard')} className={`w-full flex items-center space-x-3 text-left px-4 py-3 rounded-xl font-medium transition-all duration-200 ${activeMenu === 'dashboard' ? 'bg-gradient-to-r from-emerald-500/20 to-teal-500/10 border border-emerald-500/30 text-emerald-400 shadow-inner' : 'hover:bg-slate-800/50 text-slate-400 hover:text-slate-200'}`}>
              <span>📊</span>
              <span>Dashboard Overview</span>
            </button>
            <button onClick={() => setActiveMenu('riwayat')} className={`w-full flex items-center space-x-3 text-left px-4 py-3 rounded-xl font-medium transition-all duration-200 ${activeMenu === 'riwayat' ? 'bg-gradient-to-r from-emerald-500/20 to-teal-500/10 border border-emerald-500/30 text-emerald-400 shadow-inner' : 'hover:bg-slate-800/50 text-slate-400 hover:text-slate-200'}`}>
              <span>📜</span>
              <span className="flex-1">Riwayat Transaksi</span>
              <span className="bg-slate-800 text-slate-400 text-xs px-2 py-0.5 rounded-full font-mono">{transactions?.length || 0}</span>
            </button>
          </nav>
        </div>
        
        <div className="bg-slate-950/50 border border-slate-800/60 rounded-xl p-4 flex items-center space-x-2.5">
          <div className="w-2 h-2 rounded-full bg-emerald-400 animate-ping"></div>
          <div className="text-xs text-slate-400 font-medium">
            MySQL Status: <span className="text-emerald-400 font-semibold">Online</span>
          </div>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-5xl mx-auto space-y-8">
          
          {/* HEADER BAR */}
          <header className="flex justify-between items-center border-b border-slate-800/60 pb-5">
            <div>
              <h2 className="text-2xl font-bold tracking-tight text-white capitalize">{activeMenu === 'dashboard' ? 'Overview Real-time' : 'Arsip Riwayat'}</h2>
              <p className="text-xs text-slate-400 mt-1">Kelola data pemasukan dan pengeluaran kas dengan mudah.</p>
            </div>
            
            {/* CARD WALLET BALANCE */}
            <div className="bg-slate-900/40 border border-slate-800 px-5 py-3 rounded-xl text-right flex flex-col justify-center">
              <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Sisa Saldo Efektif</span>
              <span className={`text-xl font-bold mt-0.5 ${sisaSaldo >= 0 ? 'text-cyan-400' : 'text-rose-400'}`}>
                Rp {sisaSaldo.toLocaleString('id-ID')}
              </span>
            </div>
          </header>

          {activeMenu === 'dashboard' ? (
            <div className="space-y-8">
              {/* 2 CARD STATISTIK UTAMA */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-slate-900/40 border border-slate-800/80 p-6 rounded-2xl relative overflow-hidden group hover:border-emerald-500/30 transition-all duration-300">
                  <div className="absolute top-0 right-0 p-4 opacity-10 text-6xl text-emerald-400 select-none group-hover:scale-110 transition-transform">📈</div>
                  <span className="text-xs font-semibold text-slate-400 tracking-wider uppercase">Total Pemasukan Kas</span>
                  <p className="text-3xl font-bold text-emerald-400 mt-2 tracking-tight">Rp {totalPemasukan.toLocaleString('id-ID')}</p>
                  <div className="w-full bg-slate-950 h-1.5 rounded-full mt-4 overflow-hidden">
                    <div className="bg-gradient-to-r from-emerald-500 to-teal-400 h-full rounded-full" style={{ width: `${totalPemasukan > 0 ? 100 : 0}%` }}></div>
                  </div>
                </div>

                <div className="bg-slate-900/40 border border-slate-800/80 p-6 rounded-2xl relative overflow-hidden group hover:border-rose-500/30 transition-all duration-300">
                  <div className="absolute top-0 right-0 p-4 opacity-10 text-6xl text-rose-400 select-none group-hover:scale-110 transition-transform">📉</div>
                  <span className="text-xs font-semibold text-slate-400 tracking-wider uppercase">Total Pengeluaran Kas</span>
                  <p className="text-3xl font-bold text-rose-400 mt-2 tracking-tight">Rp {totalPengeluaran.toLocaleString('id-ID')}</p>
                  <div className="w-full bg-slate-950 h-1.5 rounded-full mt-4 overflow-hidden">
                    <div className="bg-gradient-to-r from-rose-500 to-orange-400 h-full rounded-full" style={{ width: `${totalPemasukan > 0 ? Math.min((totalPengeluaran / totalPemasukan) * 100, 100) : 0}%` }}></div>
                  </div>
                </div>
              </div>

              {/* FORM INPUT TRANSACTION */}
              <div className="bg-slate-900/30 border border-slate-800/80 rounded-2xl p-6 shadow-xl">
                <div className="border-b border-slate-800 pb-3 mb-5">
                  <h3 className="text-base font-bold text-slate-200">Tambah Transaksi Baru</h3>
                </div>
                <form onSubmit={handleFormSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-5 text-sm">
                  <div>
                    <label className="block text-slate-400 font-medium mb-1.5">Tanggal</label>
                    <input type="date" name="date" value={formData.date} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 focus:border-emerald-500/50 rounded-xl p-3 text-white focus:outline-none focus:ring-1 focus:ring-emerald-500/30 transition" />
                  </div>
                  <div>
                    <label className="block text-slate-400 font-medium mb-1.5">Jenis Aliran Dana</label>
                    <select name="category" value={formData.category} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 focus:border-emerald-500/50 rounded-xl p-3 text-white focus:outline-none focus:ring-1 focus:ring-emerald-500/30 transition">
                      <option value="Pemasukan">🟢 Pemasukan</option>
                      <option value="Pengeluaran">🔴 Pengeluaran</option>
                    </select>
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-slate-400 font-medium mb-1.5">Deskripsi / Catatan</label>
                    <input type="text" name="description" value={formData.description} onChange={handleInputChange} placeholder="Masukkan deskripsi transaksi..." className="w-full bg-slate-950 border border-slate-800 focus:border-emerald-500/50 rounded-xl p-3 text-white placeholder-slate-600 focus:outline-none focus:ring-1 focus:ring-emerald-500/30 transition" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-slate-400 font-medium mb-1.5">Nominal Uang (Rp)</label>
                    <input type="number" name="amount" value={formData.amount} onChange={handleInputChange} placeholder="Contoh: 150000" className="w-full bg-slate-950 border border-slate-800 focus:border-emerald-500/50 rounded-xl p-3 text-white placeholder-slate-600 focus:outline-none focus:ring-1 focus:ring-emerald-500/30 transition" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-gradient-to-r from-emerald-400 to-teal-500 hover:from-emerald-500 hover:to-teal-600 text-slate-950 font-bold p-3.5 rounded-xl transition-all duration-200 mt-2 text-sm tracking-wide shadow-lg shadow-emerald-500/10 active:scale-[0.99]">
                    Simpan Transaksi Ke MySQL
                  </button>
                </form>
              </div>
            </div>
          ) : (
            /* DATA LOG TABLE */
            <div className="bg-slate-900/30 border border-slate-800/80 rounded-2xl p-6 shadow-xl">
              <div className="border-b border-slate-800 pb-3 mb-4">
                <h3 className="text-base font-bold text-slate-200">Log Riwayat Buku Kas</h3>
              </div>
              <div className="overflow-x-auto rounded-xl border border-slate-800 bg-slate-950/40">
                <table className="w-full text-left text-sm border-collapse">
                  <thead>
                    <tr className="bg-slate-900/80 text-slate-400 border-b border-slate-800 font-medium">
                      <th className="p-4">Tanggal</th>
                      <th className="p-4">Deskripsi</th>
                      <th className="p-4">Kategori</th>
                      <th className="p-4 text-right">Nominal</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                    {transactions?.length === 0 ? (
                      <tr>
                        <td colSpan="4" className="text-center p-12 text-slate-600 italic">Belum ada catatan finansial di database.</td>
                      </tr>
                    ) : (
                      transactions?.map?.((t) => (
                        <tr key={t.id} className="hover:bg-slate-900/30 transition-colors duration-150">
                          <td className="p-4 text-slate-400 font-mono text-xs">{t.date}</td>
                          <td className="p-4 font-medium text-slate-200">{t.description}</td>
                          <td className="p-4">
                            <span className={`px-2.5 py-1 rounded-lg text-xs font-semibold ${t.category === 'Pemasukan' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'}`}>
                              {t.category}
                            </span>
                          </td>
                          <td className={`p-4 text-right font-bold font-mono ${t.category === 'Pemasukan' ? 'text-emerald-400' : 'text-rose-400'}`}>
                            Rp {parseFloat(t.amount || 0).toLocaleString('id-ID')}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}

export default App;
